            // Removing the ' or adding another one fixes it.
            migrationBuilder.Sql("""
                /* It's a procedure */
                create procedure dbo.proc1 as select 1;
                go

                /* Another one */
                create procedure dbo.proc2 as select 2;
            """);
        }

