Incorrect compensation for bool with value converter in CASE

The `CASE` in SQL below is missing `= 10`. Hence the query returns incorrect data (or might fail to process on DB side if there's no default conversion to bool). SQL Server works by luck, because of `SearchConditionConverter`.

```csharp
using var db = new TestContext();
db.Database.EnsureDeleted();
db.Database.EnsureCreated();
db.TestEntities.AddRange(
    new TestEntity { Id = 1, Hours = 2.5, HourlyRate = 200, IsInternal = false },
    new TestEntity { Id = 2, Hours = 1.0, HourlyRate = 300, IsInternal = true }
);
db.SaveChanges();
var q = db.TestEntities
    .OrderBy(e => e.Id)
    .Select(e => new
    {
        e.Id,
        Costs = e.IsInternal ?? false ? 0 : e.Hours * e.HourlyRate,
    });
var sql = q.ToQueryString();
Console.WriteLine(sql);
foreach (var item in q)
{
    Console.WriteLine($"Id: {item.Id}, Costs: {item.Costs}");
}
Console.WriteLine("===");
var e = db.TestEntities
    .AsEnumerable()
    .OrderBy(e => e.Id)
    .Select(e => new
    {
        e.Id,
        Costs = e.IsInternal ?? false ? 0 : e.Hours * e.HourlyRate,
    });
foreach (var item in e)
{
    Console.WriteLine($"Id: {item.Id}, Costs: {item.Costs}");
}

 public class TestEntity
 {
     public int Id { get; set; }
     public double Hours { get; set; }
     public double HourlyRate { get; set; }
     public bool? IsInternal { get; set; }
 }
 public class TestContext : DbContext
 {
     public DbSet<TestEntity> TestEntities { get; set; }

     protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
         => optionsBuilder.UseSqlite("Data Source=foobar.db");

     protected override void OnModelCreating(ModelBuilder modelBuilder)
     {
         modelBuilder.Entity<TestEntity>(builder =>
         {
             builder.Property(a => a.IsInternal).HasConversion<TestConverter>();
         });
     }
 }
 public class TestConverter : ValueConverter<bool?, short?>
 {
     public TestConverter()
         : base(
             x => x == true ? (short?)10 : (short?)99,
             _ => default,
             convertsNulls: true)
     { }
 }
